# Phase 7 Task 4: Design Mode IPC Plumbing

## CONTEXT
Connect the renderer to Claude for design mode conversations. Messages in design mode use the design prompt and populate the spec panel.

## REQUIREMENTS

### 1. New IPC Handler (main.js)

```javascript
// Handle design mode message
ipcMain.handle('send-design-message', async (event, { message, currentSpec, history }) => {
  try {
    console.log('[Main] Design mode message received');

    // Build design prompt
    const prompt = claudeManager.buildDesignPrompt(message, currentSpec, history);

    // Send to Claude
    const response = await claudeManager.sendPrompt(prompt);

    // Parse response (just return the spec text)
    const parsed = claudeManager.parseDesignResponse 
      ? claudeManager.parseDesignResponse(response)
      : { spec: response.trim(), raw: response };

    return {
      success: true,
      spec: parsed.spec
    };
  } catch (err) {
    console.error('[Main] Design message error:', err);
    return {
      success: false,
      error: err.message
    };
  }
});
```

### 2. Modify sendChatMessage in renderer.js

When in design mode, use the design IPC channel:

```javascript
async function sendChatMessage() {
  const message = chatInput.value.trim();
  if (!message || isProcessing) return;

  chatInput.value = '';
  isProcessing = true;

  // Check for /design command
  let actualMessage = message;
  if (message.startsWith('/design')) {
    if (!designMode) {
      enterDesignMode();
    }
    actualMessage = message.replace('/design', '').trim() || 'Help me design a 3D model';
  }

  // Check for /build command
  if (message === '/build' || message.toLowerCase() === 'build it') {
    await handleBuildCommand();
    isProcessing = false;
    return;
  }

  // Add user message to chat
  addMessage('user', message);

  try {
    if (designMode) {
      // Design mode: get spec from Claude
      setProcessing('claude');

      const currentSpec = document.getElementById('spec-editor').value;
      const history = messageHistory
        .filter(msg => msg.role === 'user' || msg.role === 'assistant')
        .map(msg => ({ role: msg.role, content: msg.content }));

      const result = await ipcRenderer.invoke('send-design-message', {
        message: actualMessage,
        currentSpec,
        history
      });

      setProcessing(null);

      if (result.success) {
        // Update spec panel
        document.getElementById('spec-editor').value = result.spec;

        // Add brief confirmation to chat
        addMessage('assistant', 'Spec updated. Review it in the panel and click Build when ready.');

        // Mark dirty
        isDirty = true;
        updateWindowTitle();
      } else {
        addMessage('error', result.error);
      }
    } else {
      // Normal mode: existing code generation flow
      // ... (existing sendChatMessage logic)
    }
  } catch (err) {
    addMessage('error', err.message);
    setProcessing(null);
  } finally {
    isProcessing = false;
    chatInput.disabled = false;
    sendButton.disabled = false;
    chatInput.focus();
  }
}
```

