# Phase 7 Task 5: Build Command Implementation

## CONTEXT
When user is done with the spec, they click Build (or type /build) to generate code from the spec and render the model.

## REQUIREMENTS

### 1. Build Button Handler (renderer.js)

```javascript
document.getElementById('spec-build-button').addEventListener('click', () => {
  handleBuildCommand();
});

async function handleBuildCommand() {
  const spec = document.getElementById('spec-editor').value.trim();

  if (!spec) {
    addMessage('error', 'No spec to build. Create a design first.');
    return;
  }

  try {
    isProcessing = true;
    setProcessing('claude');

    // Send spec to Claude for code generation
    const result = await ipcRenderer.invoke('build-from-spec', { spec });

    if (result.success) {
      // Save undo state
      saveUndo();

      // Update current code
      currentCode = result.code;

      // Add message to chat
      addMessage('assistant', result.explanation);

      // Exit design mode (hide spec panel)
      exitDesignMode();

      // Load the model
      if (result.empty) {
        clearViewport();
        setProcessing(null);
      } else {
        loadShapes(result.shapes, result.volume);
      }

      // Mark dirty
      isDirty = true;
      currentFilePath = null; // New model, needs Save As
      projectName = 'untitled';
      updateWindowTitle();
    } else {
      setProcessing(null);
      addMessage('error', `Build failed: ${result.error}`);
    }
  } catch (err) {
    setProcessing(null);
    addMessage('error', `Build error: ${err.message}`);
  } finally {
    isProcessing = false;
  }
}
```

### 2. IPC Handler for Build (main.js)

```javascript
ipcMain.handle('build-from-spec', async (event, { spec }) => {
  try {
    console.log('[Main] Building from spec...');

    // Create a prompt that asks Claude to generate code from the spec
    const prompt = buildCodeFromSpecPrompt(spec);

    // Send to Claude
    const response = await claudeManager.sendPrompt(prompt);

    // Parse response (expecting code)
    const parsed = claudeManager.parseResponse(response);

    if (!parsed.code) {
      return {
        success: false,
        error: 'Claude did not generate code from the spec',
        explanation: parsed.explanation
      };
    }

    // Execute the code
    const execResult = await pythonManager.executeCode(parsed.code);

    if (execResult.success) {
      return {
        success: true,
        code: parsed.code,
        explanation: parsed.explanation,
        shapes: execResult.shapes,
        volume: execResult.volume,
        empty: execResult.empty
      };
    } else {
      return {
        success: false,
        error: execResult.error,
        explanation: parsed.explanation
      };
    }
  } catch (err) {
    console.error('[Main] Build from spec error:', err);
    return {
      success: false,
      error: err.message
    };
  }
});
```

